targets.query:
from(bucket: "sensor_telemetry")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "sensor_reading")
  |> filter(fn: (r) => r.device_code == "${device_id}")
  |> filter(fn: (r) => r._field == "turbidity_ntu" or r._field == "flow_lpm" or r._field == "flow_total_liters")
  |> group(columns: ["_field"])
  |> reduce(
      fn: (r, accumulator) => ({
          min:   (r._value < accumulator.min) ? r._value : accumulator.min,
          max:   (r._value > accumulator.max) ? r._value : accumulator.max,
          sum:   accumulator.sum + r._value,
          count: accumulator.count + 1.0
      }),
      identity: {min: 9999.0, max: -9999.0, sum: 0.0, count: 0.0}
  )
  |> map(fn: (r) => ({r with mean: r.sum / r.count}))
